def vscore(sc):
    return int((sc.get('emotional',0)*2 + sc.get('relatability',0)*2 + sc.get('clarity',0)*2 + sc.get('surprise',0)*1.5 + sc.get('tension',0)*1 + sc.get('visual',0)*1 + sc.get('data_ready',0)*0.5 + sc.get('originality',0)*0.5) / 10.5)
for idea in ideas:
    idea['vs'] = vscore(idea['sc'])
if __name__ == '__main__':
    print(f'BATCH_BI: {len(ideas)} ideas')
    for i in sorted(ideas, key=lambda x: -x['vs']):
        print(f'  vs={i["vs"]:3d}  {i["id"]}')
